      "order": 18,
      "sequence_id": "CS-018",
      "group": "Mobile and laptop sequence",
      "topic": "Laptop hardware",
      "slug": "laptop-hardware",
      "material_path": "materials/course-sequence/laptop-hardware.md",
      "comptia_area": "Mobile Devices",
      "route_id": "MAP-004",
