      "order": 21,
      "sequence_id": "CS-021",
      "group": "Troubleshooting sequence",
      "topic": "Troubleshooting methodology",
      "slug": "troubleshooting-methodology",
      "material_path": "materials/course-sequence/troubleshooting-methodology.md",
