      "group": "Troubleshooting sequence",
      "topic": "Troubleshooting storage devices",
      "slug": "troubleshooting-storage-devices",
      "material_path": "materials/course-sequence/troubleshooting-storage-devices.md",
      "comptia_area": "Hardware and Networking Troubleshooting",
      "route_id": "MAP-005",
