      "topic": "Troubleshooting video issues",
      "slug": "troubleshooting-video-issues",
      "material_path": "materials/course-sequence/troubleshooting-video-issues.md",
      "comptia_area": "Hardware and Networking Troubleshooting",
      "route_id": "MAP-005",
